By mfish\n  licenseUrl: http://www.mfish.com.cn\n  version: 版本号:V2.1.1\n  termsOfServiceUrl: http://www.mfish.com.cn\n  ignoreServers: mf-gateway,mf-monitor\n  contact:\n    name: mfish\n    email: qiufeng9862@qq.com\n    url: http://www.mfish.com.cn\nspringdoc:\n  swagger-ui:\n    enabled: true\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n    default-models-expand-depth: -1\n    docExpansion: none\n  api-docs:\n    enabled: true\n    path: /v3/api-docs\n  use-management-port: false\n  default-flat-param-object: true', '832d798b554120710e6615813bf9d699', '2026-02-08 10:36:25', '2026-02-08 10:36:47', 'nacos', '0:0:0:0:0:0:0:1', '', 'public', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (3, 'mf-oauth-dev.yml', 'DEFAULT_GROUP', 'swagger:\r\n  title: \'摸鱼认证中心\'\r\n  prefix: /oauth2\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 搜索指定包别名\r\n  type-aliases-package: cn.com.mfish.oauth.mapper\r\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/**/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  thymeleaf:\r\n    cache: false\r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_oauth?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\nredisCache:\r\n  expire: 50400\r\n  keyPrefix: sso_cache\r\nredisSession:\r\n  expire: 50400\r\n  keyPrefix: sso_session\r\noauth2:\r\n  expire:\r\n    code: 180\r\n    token: 21600\r\n    refreshToken: 604800\r\n  login:\r\n    mutex: false\r\n  user:\r\n    autoCreate: false\r\n  token:\r\n    sm4key: 143be1ae6ee10b048f7e441cec2a9803\r\nwechat:\r\n  miniapp:\r\n    appId: wx*************e34a3\r\n    secret: a65e*************fa222\r\ngitee:\r\n  clientId: a83ea66522fef5f382c6aaffa875c7e87b21d3933277c44a326cd3407fc0b651\r\n  clientSecret: 3ebdce2afcb4a7df9b16355f60d898d452f4d9cf8ad1ab8279bb3bb465e614db\r\n  redirectUri: http://localhost:5186/giteeOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=gitee\r\ngithub:\r\n  clientId: Ov23li7oH0Djw3ZEJCoJ\r\n  clientSecret: ada9a510b3bde542e7510142f07d32a5f6bed131\r\n  redirectUri: http://localhost:5186/githubOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=github', '34d1ab06f05a4c251d9cb4ce7547badc', '2026-02-08 10:37:25', '2026-02-08 10:37:25', 'nacos_namespace_migrate', '0:0:0:0:0:0:0:1', '', '', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (4, 'mf-oauth-dev.yml', 'DEFAULT_GROUP', 'swagger:\r\n  title: \'摸鱼认证中心\'\r\n  prefix: /oauth2\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 搜索指定包别名\r\n  type-aliases-package: cn.com.mfish.oauth.mapper\r\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/**/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  thymeleaf:\r\n    cache: false\r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_oauth?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\nredisCache:\r\n  expire: 50400\r\n  keyPrefix: sso_cache\r\nredisSession:\r\n  expire: 50400\r\n  keyPrefix: sso_session\r\noauth2:\r\n  expire:\r\n    code: 180\r\n    token: 21600\r\n    refreshToken: 604800\r\n  login:\r\n    mutex: false\r\n  user:\r\n    autoCreate: false\r\n  token:\r\n    sm4key: 143be1ae6ee10b048f7e441cec2a9803\r\nwechat:\r\n  miniapp:\r\n    appId: wx*************e34a3\r\n    secret: a65e*************fa222\r\ngitee:\r\n  clientId: a83ea66522fef5f382c6aaffa875c7e87b21d3933277c44a326cd3407fc0b651\r\n  clientSecret: 3ebdce2afcb4a7df9b16355f60d898d452f4d9cf8ad1ab8279bb3bb465e614db\r\n  redirectUri: http://localhost:5186/giteeOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=gitee\r\ngithub:\r\n  clientId: Ov23li7oH0Djw3ZEJCoJ\r\n  clientSecret: ada9a510b3bde542e7510142f07d32a5f6bed131\r\n  redirectUri: http://localhost:5186/githubOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=github', '34d1ab06f05a4c251d9cb4ce7547badc', '2026-02-08 10:37:25', '2026-02-08 10:37:25', 'nacos', '0:0:0:0:0:0:0:1', '', 'public', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (5, 'mf-sys-dev.yml', 'DEFAULT_GROUP', 'swagger:\r\n  title: \'摸鱼系统业务中心\'\r\n  prefix: /sys\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/sys/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_system?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\ncode:\r\n  template:\r\n    keys:\r\n      - src/main/java/${packageName}/controller/${entityName}Controller.java.ftl\r\n      - src/main/java/${packageName}/entity/${entityName}.java.ftl\r\n      - src/main/java/${packageName}/mapper/${entityName}Mapper.java.ftl\r\n      - src/main/java/${packageName}/mapper/xml/${entityName}Mapper.xml.ftl\r\n      - src/main/java/${packageName}/req/Req${entityName}.java.ftl\r\n      - src/main/java/${packageName}/service/${entityName}Service.java.ftl\r\n      - src/main/java/${packageName}/service/impl/${entityName}ServiceImpl.java.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName#uncap_first}.data.ts.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName}Modal.vue.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName}ViewModal.vue.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/index.vue.ftl\r\n      - mfish-nocode-view/src/api/${apiPrefix}/model/${entityName}Model.ts.ftl\r\n      - mfish-nocode-view/src/api/${apiPrefix}/${entityName}.ts.ftl\r\n    path: template\r\n  savePath:\r\n    #前端地址\r\n    front: E:/webcode\r\n    #后端地址（需要指定到具体模块路径）\r\n    back: E:/javacode/mfish-nocode-pro/mf-business/mf-sys', '03eedd7cd6a21c36288215e8c4ee9c97', '2026-02-08 10:37:54', '2026-02-08 10:37:54', 'nacos_namespace_migrate', '0:0:0:0:0:0:0:1', '', '', NULL, NULL, NULL, 'yaml', NULL, '');
