INSERT INTO `his_config_info` VALUES (0, 1, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  autoconfigure:\r\n    exclude:\r\n      - org.mybatis.spring.boot.autoconfigure.MybatisAutoConfiguration\r\n  data:\r\n    redis:\r\n      host: localhost\r\n      port: 6379\r\n      password: \"1qaz@WSX\"\r\n      database: 5\r\n      timeout: 10s\r\n      lettuce:\r\n        pool:\r\n          # 连接池中的最小空闲连接\r\n          min-idle: 0\r\n          # 连接池中的最大空闲连接\r\n          max-idle: 8\r\n          # 连接池的最大数据库连接数\r\n          max-active: 8\r\n          # #连接池最大阻塞等待时间（使用负值表示没有限制）\r\n          max-wait: -1ms\r\n  servlet:\r\n    multipart:\r\n      # 单个文件大小\r\n      max-file-size: 1200MB\r\n      # 设置总上传的文件大小\r\n      max-request-size: 1200MB\r\n  ai:\r\n    openai:\r\n      api-key: sk-or-v1-b4**************************************a99b135dae3b\r\n      base-url: https://openrouter.ai/api\r\n      chat:\r\n        options:\r\n          model: meta-llama/llama-3.3-70b-instruct:free\r\n          max-tokens: 1000\r\n          temperature: 0.7\r\n    ollama:\r\n      base-url: http://localhost:11434\r\n      chat:\r\n        model: qwen3:8b\r\n# feign 配置\r\nfeign:\r\n  sentinel:\r\n    enabled: true\r\n  okhttp: \r\n    enabled: true\r\n  httpclient:\r\n    enabled: false\r\n  client:\r\n    config:\r\n      default:\r\n        connectTimeout: 10000\r\n        readTimeout: 10000\r\n  compression:\r\n    request:\r\n      enabled: false\r\n    response:\r\n      enabled: false\r\n\r\n# 暴露监控端点\r\nmanagement:\r\n  health:\r\n    sentinel:\r\n    # 关闭健康检查，避免日志刷屏\r\n      enabled: false\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: \r\n          - info\r\n          - health\r\n          - metrics\r\n          - prometheus\r\n  endpoint:\r\n    health:\r\n      show-details: always\r\nlogging:\r\n  config: classpath:logback-logstash.xml\r\nlog:\r\n  level: info\r\n  maxSize: 30MB\r\n# 临时缓存存储时间（单位：天）\r\ncache:\r\n  temp:\r\n    time: 7\r\nDBConnect:\r\n  password:\r\n    privateKey: 54f0e36b98cf63c3bc6185b61c6e4f2a6e1df3bdeb293a50d7b0bc66881c2419\r\nswagger:\r\n  title: \'摸鱼低代码平台\'\r\n  enabled: true\r\n  description: 摸鱼框架接口文档\r\n  license: Powered By mfish\r\n  licenseUrl: http://www.mfish.com.cn\r\n  version: 版本号:V2.1.1\r\n  termsOfServiceUrl: http://www.mfish.com.cn\r\n  ignoreServers: mf-gateway,mf-monitor\r\n  contact:\r\n    name: mfish\r\n    email: qiufeng9862@qq.com\r\n    url: http://www.mfish.com.cn\r\nspringdoc:\r\n  swagger-ui:\r\n    enabled: true\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n    default-models-expand-depth: -1\r\n    docExpansion: none\r\n  api-docs:\r\n    enabled: true\r\n    path: /v3/api-docs\r\n  use-management-port: false\r\n  default-flat-param-object: true', '50c0f5d180851eb0b4f5159589324a8d', '2026-02-08 10:36:25', '2026-02-08 10:36:25', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (2, 2, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  autoconfigure:\r\n    exclude:\r\n      - org.mybatis.spring.boot.autoconfigure.MybatisAutoConfiguration\r\n  data:\r\n    redis:\r\n      host: localhost\r\n      port: 6379\r\n      password: \"1qaz@WSX\"\r\n      database: 5\r\n      timeout: 10s\r\n      lettuce:\r\n        pool:\r\n          # 连接池中的最小空闲连接\r\n          min-idle: 0\r\n          # 连接池中的最大空闲连接\r\n          max-idle: 8\r\n          # 连接池的最大数据库连接数\r\n          max-active: 8\r\n          # #连接池最大阻塞等待时间（使用负值表示没有限制）\r\n          max-wait: -1ms\r\n  servlet:\r\n    multipart:\r\n      # 单个文件大小\r\n      max-file-size: 1200MB\r\n      # 设置总上传的文件大小\r\n      max-request-size: 1200MB\r\n  ai:\r\n    openai:\r\n      api-key: sk-or-v1-b4**************************************a99b135dae3b\r\n      base-url: https://openrouter.ai/api\r\n      chat:\r\n        options:\r\n          model: meta-llama/llama-3.3-70b-instruct:free\r\n          max-tokens: 1000\r\n          temperature: 0.7\r\n    ollama:\r\n      base-url: http://localhost:11434\r\n      chat:\r\n        model: qwen3:8b\r\n# feign 配置\r\nfeign:\r\n  sentinel:\r\n    enabled: true\r\n  okhttp: \r\n    enabled: true\r\n  httpclient:\r\n    enabled: false\r\n  client:\r\n    config:\r\n      default:\r\n        connectTimeout: 10000\r\n        readTimeout: 10000\r\n  compression:\r\n    request:\r\n      enabled: false\r\n    response:\r\n      enabled: false\r\n\r\n# 暴露监控端点\r\nmanagement:\r\n  health:\r\n    sentinel:\r\n    # 关闭健康检查，避免日志刷屏\r\n      enabled: false\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: \r\n          - info\r\n          - health\r\n          - metrics\r\n          - prometheus\r\n  endpoint:\r\n    health:\r\n      show-details: always\r\nlogging:\r\n  config: classpath:logback-logstash.xml\r\nlog:\r\n  level: info\r\n  maxSize: 30MB\r\n# 临时缓存存储时间（单位：天）\r\ncache:\r\n  temp:\r\n    time: 7\r\nDBConnect:\r\n  password:\r\n    privateKey: 54f0e36b98cf63c3bc6185b61c6e4f2a6e1df3bdeb293a50d7b0bc66881c2419\r\nswagger:\r\n  title: \'摸鱼低代码平台\'\r\n  enabled: true\r\n  description: 摸鱼框架接口文档\r\n  license: Powered By mfish\r\n  licenseUrl: http://www.mfish.com.cn\r\n  version: 版本号:V2.1.1\r\n  termsOfServiceUrl: http://www.mfish.com.cn\r\n  ignoreServers: mf-gateway,mf-monitor\r\n  contact:\r\n    name: mfish\r\n    email: qiufeng9862@qq.com\r\n    url: http://www.mfish.com.cn\r\nspringdoc:\r\n  swagger-ui:\r\n    enabled: true\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n    default-models-expand-depth: -1\r\n    docExpansion: none\r\n  api-docs:\r\n    enabled: true\r\n    path: /v3/api-docs\r\n  use-management-port: false\r\n  default-flat-param-object: true', '50c0f5d180851eb0b4f5159589324a8d', '2026-02-08 10:36:47', '2026-02-08 10:36:47', 'nacos', '0:0:0:0:0:0:0:1', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (0, 3, 'mf-oauth-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼认证中心\'\r\n  prefix: /oauth2\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 搜索指定包别名\r\n  type-aliases-package: cn.com.mfish.oauth.mapper\r\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/**/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  thymeleaf:\r\n    cache: false\r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_oauth?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\nredisCache:\r\n  expire: 50400\r\n  keyPrefix: sso_cache\r\nredisSession:\r\n  expire: 50400\r\n  keyPrefix: sso_session\r\noauth2:\r\n  expire:\r\n    code: 180\r\n    token: 21600\r\n    refreshToken: 604800\r\n  login:\r\n    mutex: false\r\n  user:\r\n    autoCreate: false\r\n  token:\r\n    sm4key: 143be1ae6ee10b048f7e441cec2a9803\r\nwechat:\r\n  miniapp:\r\n    appId: wx*************e34a3\r\n    secret: a65e*************fa222\r\ngitee:\r\n  clientId: a83ea66522fef5f382c6aaffa875c7e87b21d3933277c44a326cd3407fc0b651\r\n  clientSecret: 3ebdce2afcb4a7df9b16355f60d898d452f4d9cf8ad1ab8279bb3bb465e614db\r\n  redirectUri: http://localhost:5186/giteeOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=gitee\r\ngithub:\r\n  clientId: Ov23li7oH0Djw3ZEJCoJ\r\n  clientSecret: ada9a510b3bde542e7510142f07d32a5f6bed131\r\n  redirectUri: http://localhost:5186/githubOauth2\r\n  bindUri: http://localhost:5186/tenant/info/1?callback=github', '34d1ab06f05a4c251d9cb4ce7547badc', '2026-02-08 10:37:24', '2026-02-08 10:37:25', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 4, 'mf-sys-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼系统业务中心\'\r\n  prefix: /sys\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/sys/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_system?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\ncode:\r\n  template:\r\n    keys:\r\n      - src/main/java/${packageName}/controller/${entityName}Controller.java.ftl\r\n      - src/main/java/${packageName}/entity/${entityName}.java.ftl\r\n      - src/main/java/${packageName}/mapper/${entityName}Mapper.java.ftl\r\n      - src/main/java/${packageName}/mapper/xml/${entityName}Mapper.xml.ftl\r\n      - src/main/java/${packageName}/req/Req${entityName}.java.ftl\r\n      - src/main/java/${packageName}/service/${entityName}Service.java.ftl\r\n      - src/main/java/${packageName}/service/impl/${entityName}ServiceImpl.java.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName#uncap_first}.data.ts.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName}Modal.vue.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/${entityName}ViewModal.vue.ftl\r\n      - mfish-nocode-view/src/views/${apiPrefix}/${entityName#kebab-case}/index.vue.ftl\r\n      - mfish-nocode-view/src/api/${apiPrefix}/model/${entityName}Model.ts.ftl\r\n      - mfish-nocode-view/src/api/${apiPrefix}/${entityName}.ts.ftl\r\n    path: template\r\n  savePath:\r\n    #前端地址\r\n    front: E:/webcode\r\n    #后端地址（需要指定到具体模块路径）\r\n    back: E:/javacode/mfish-nocode-pro/mf-business/mf-sys', '03eedd7cd6a21c36288215e8c4ee9c97', '2026-02-08 10:37:54', '2026-02-08 10:37:54', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 5, 'mf-storage-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼文件管理\'\r\n  prefix: /storage\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/storage/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_system?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\nstorage:\r\n  active: local\r\n  address: http://localhost:8888/storage/file/\r\n  local:\r\n    storagePath: E:/storage\r\n  aliyun:\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    accessKeyId: LTAI5***********FsgT\r\n    accessKeySecret: ZtZGF***************JADjS2f\r\n    bucketName: landwise\r\n  qiniu:\r\n    domain: http://cdn.mfish.com.cn\r\n    accessKey: cHlX4*******************cdsexgvP\r\n    secretKey: QPACH*******************1vEa1t4S\r\n    bucket: mfish-nocode', '5d34bf317473dbb57abe28db773a7834', '2026-02-08 10:38:14', '2026-02-08 10:38:15', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 6, 'mf-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  cloud:\r\n    gateway:\r\n      server:\r\n        webflux:\r\n          globalcors:\r\n            cors-configurations:\r\n              \'[/**]\':\r\n                max-age: 3600\r\n                allowed-origin-patterns: \"*\"\r\n                allowed-headers: \"*\"\r\n                allow-credentials: true\r\n                allowed-methods:\r\n                  - GET\r\n                  - POST\r\n                  - DELETE\r\n                  - PUT\r\n                  - OPTION \r\n          discovery:\r\n            locator:\r\n              lowerCaseServiceId: true\r\n              enabled: true\r\n          routes:\r\n            # 认证中心\r\n            - id: oauth2\r\n              uri: lb://mf-oauth\r\n              predicates:\r\n                - Path=/oauth2/**\r\n              filters:\r\n                - CacheFilter\r\n                # 验证码处理\r\n                - CheckCodeFilter\r\n                - StripPrefix=1\r\n            # 测试中心\r\n            - id: test\r\n              uri: lb://mf-test\r\n              predicates:\r\n                - Path=/test/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: sys\r\n              uri: lb://mf-sys\r\n              predicates:\r\n                - Path=/sys/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: demo\r\n              uri: lb://mf-demo\r\n              predicates:\r\n                - Path=/demo/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: storage\r\n              uri: lb://mf-storage\r\n              predicates:\r\n                - Path=/storage/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: scheduler\r\n              uri: lb://mf-scheduler\r\n              predicates:\r\n                - Path=/scheduler/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: nocode\r\n              uri: lb://mf-nocode\r\n              predicates:\r\n                - Path=/nocode/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: workflow\r\n              uri: lb://mf-workflow\r\n              predicates:\r\n                - Path=/workflow/**\r\n              filters:\r\n                - StripPrefix=1\r\n            - id: ai\r\n              uri: lb://mf-ai\r\n              predicates:\r\n                - Path=/ai/**\r\n              filters:\r\n                - StripPrefix=1\r\n# 安全配置\r\nsecurity:\r\n  # 验证码\r\n  captcha:\r\n    enabled: true\r\n    type: math\r\n    # 网关校验直接返回\r\n    gatewayCheckCaptcha:\r\n      # - /oauth2/authorize\r\n      # 网关校验，自己服务返回\r\n    selfCheckCaptcha:\r\n      - /oauth2/authorize?loginType=user_password\r\n  # 防止XSS攻击\r\n  xss:\r\n    enabled: true\r\n    excludeUrls:\r\n  # 不校验白名单\r\n  ignore:\r\n    whites:\r\n      - /oauth2/user/revoke\r\n      - /oauth2/accessToken\r\n      - /oauth2/authorize\r\n      - /oauth2/sendMsg\r\n      - /oauth2/qrCodeLogin/*\r\n      - /oauth2/wx/bind/**\r\n      - /oauth2/static/**\r\n      - /oauth2/gitee/token/**\r\n      - /oauth2/gitee/url\r\n      - /oauth2/github/token/**\r\n      - /oauth2/github/url\r\n      - /storage/file/*.*\r\n      - /code/**\r\n      - /test/**\r\n      - /*/v3/api-docs\r\n# swagger configuration\r\nspringdoc: \r\n  webjars: \r\n    # 设置为空，不要前缀，不配置这个就需要多加一层路径`/webjars`->`http:host:网关ip/webjars/swagger-ui/index.html`\r\n    prefix:', '7449108066fd0424a089741cb5802608', '2026-02-08 10:38:38', '2026-02-08 10:38:39', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 7, 'mf-scheduler-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼调度中心\'\r\n  prefix: /scheduler\r\n# mybatis配置\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/scheduler/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_scheduler?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\norg:\r\n  quartz:\r\n    scheduler:\r\n      instanceName: MfishClusteredScheduler\r\n      instanceId: AUTO\r\n    threadPool:\r\n      poolClass: org.quartz.simpl.SimpleThreadPool\r\n      threadCount: 50\r\n      threadPriority: 5\r\n    jobStore:\r\n      jdbcClass: org.quartz.impl.jdbcjobstore.JobStoreTX\r\n      driverDelegateClass: org.quartz.impl.jdbcjobstore.StdJDBCDelegate\r\n      useProperties: true\r\n      isClustered: true\r\n      tablePrefix: QRTZ_\r\n      dataSource: mf_scheduler\r\n      clusterCheckinInterval: 20000\r\n      misfireThreshold: 60000\r\n#rocketmq配置信息\r\nrocketmq:\r\n  #nameservice服务器地址（多个以英文逗号隔开）\r\n  name-server: 127.0.0.1:9876\r\n  #生产者配置\r\n  producer:\r\n    #组名\r\n    group: mfish-scheduler-group\r\n    sendMessageTimeout: 300000\r\n    #目的地（topic:tag）\r\n    #topic\r\n    topic: mfish-scheduler-topic', '804951d75ca731c1bd02f89f2868abe1', '2026-02-08 10:39:07', '2026-02-08 10:39:07', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 8, 'mf-workflow-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼工作流服务\'\r\n  prefix: /workflow\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/workflow/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    dynamic:\r\n      hikari:\r\n        # ========== 连接池核心参数 ==========\r\n        minimum-idle: 5              # 连接池最小空闲连接数\r\n        maximum-pool-size: 20        # 连接池最大连接数\r\n        idle-timeout: 300000         # 5分钟，空闲连接存活最大时间\r\n        max-lifetime: 1800000        # 30分钟 连接最大存活时间\r\n        connection-timeout: 30000    # 连接超时时间\r\n        validation-timeout: 5000\r\n        # ========== 连接检测 ==========\r\n        connection-test-query: SELECT 1\r\n        # ========== PreparedStatement 缓存 ==========\r\n        data-source-properties:\r\n          cachePrepStmts: true\r\n          prepStmtCacheSize: 250\r\n          prepStmtCacheSqlLimit: 2048\r\n          useServerPrepStmts: true\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_workflow?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&nullCatalogMeansCurrent=true\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\n# Flowable 会自动建表\r\nflowable:\r\n  # 自动更新数据库结构\r\n  database-schema-update: true\r\n  # 启用异步执行器\r\n  async-executor-activate: true\r\n  eventregistry:\r\n    enabled: false\r\n  # 检查流程定义\r\n#  check-process-definitions: false', '09248143eabcad1efb0939f571a1005b', '2026-02-08 10:40:11', '2026-02-08 10:40:12', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 9, 'mf-monitor-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼监控中心\'\r\nspring: \r\n  security:\r\n    user:\r\n      name: admin\r\n      password: 123456\r\n  boot:\r\n    admin:\r\n      ui:\r\n        title: 摸鱼监控中心', 'cf16dec113c8fcf0728533a30e679e0a', '2026-02-08 10:40:34', '2026-02-08 10:40:35', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 10, 'mf-nocode-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼无代码中心\'\r\n  prefix: /nocode\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/nocode/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_nocode?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\nstorage:\r\n  active: local\r\n  address: http://localhost:8888/storage/file/\r\n  local:\r\n    storagePath: E:/storage\r\n  aliyun:\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    accessKeyId: LTAI5***********FsgT\r\n    accessKeySecret: ZtZGF***************JADjS2f\r\n    bucketName: landwise\r\n  qiniu:\r\n    domain: http://cdn.mfish.com.cn\r\n    accessKey: cHlX4*******************cdsexgvP\r\n    secretKey: QPACH*******************1vEa1t4S\r\n    bucket: mfish-nocode', '9da1faf051318a3b52a6c58f8d1b3773', '2026-02-08 10:40:57', '2026-02-08 10:40:58', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"text\"}');
INSERT INTO `his_config_info` VALUES (0, 11, 'mf-demo-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼样例服务\'\r\n  prefix: /demo\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/demo/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_demo?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭', 'df5971c7c04f34636ac6b9c790b3073d', '2026-02-08 10:41:20', '2026-02-08 10:41:21', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 12, 'mf-ai-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼AI中心\'\r\n  prefix: /ai\r\nmybatis-plus:\r\n  # 配置mapper的扫描，找到所有的mapper.xml映射文件\r\n  mapper-locations: classpath*:cn/com/mfish/ai/mapper/**/*Mapper.xml\r\n  global-config:\r\n    # 关闭MP3.0自带的banner\r\n    banner: false\r\n    db-config:\r\n      #主键类型  0:\"数据库ID自增\",1:\"该类型为未设置主键类型\", 2:\"用户输入ID\",3:\"全局唯一ID (数字类型唯一ID)\", 4:\"全局唯一ID UUID\",5:\"字符串全局唯一ID (idWorker 的字符串表示)\";\r\n      #id-type: 0\r\n      # 默认数据库表下划线命名\r\n      table-underline: true\r\n      #逻辑删除 删除前\r\n      logic-not-delete-value: 0\r\n      #逻辑删除 删除后\r\n      logic-delete-value: 1\r\n  configuration:\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    #log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    # 返回类型为Map,显示null对应的字段\r\n    call-setters-on-nulls: true\r\n    map-underscore-to-camel-case: true\r\n    auto-mapping-behavior: full\r\n    jdbc-type-for-null:\r\nspring: \r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\r\n      datasource:\r\n        # 主库数据源\r\n        master:\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n          url: jdbc:mysql://localhost:3306/mf_demo?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\r\n          username: root\r\n          password: 123456\r\n          # 从库数据源\r\n          # slave:\r\n            # username: \r\n            # password: \r\n            # url: \r\n            # driver-class-name: \r\n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\r\n  ai:\r\n    openai:\r\n      api-key: sk-or-v1-b4**************************************a99b135dae3b\r\n      base-url: https://openrouter.ai/api\r\n      chat:\r\n        options:\r\n          model: meta-llama/llama-3.3-70b-instruct:free\r\n          max-tokens: 1000\r\n          temperature: 0.7\r\n    ollama:\r\n      base-url: http://localhost:11434\r\n      chat:\r\n        model: qwen3:8b', 'c36840b577c0940c00d629f2497cc706', '2026-02-08 10:41:48', '2026-02-08 10:41:48', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 13, 'mf-consume-dev.yml', 'DEFAULT_GROUP', '', 'swagger:\r\n  title: \'摸鱼调度中心-MQ消费端测试\'\r\n#rocketmq配置信息\r\nrocketmq:\r\n  #生产者配置\r\n  consumer:\r\n    nameServer: 127.0.0.1:9876\r\n    #topic\r\n    topic: mfish-scheduler-topic\r\n    #组名\r\n    group: mfish-scheduler-group', '3b38a5c258a1bdd32b06844e87a4e1f1', '2026-02-08 10:42:03', '2026-02-08 10:42:04', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 14, 'sentinel-mf-gateway', 'DEFAULT_GROUP', '', '[\r\n    {\r\n        \"resource\": \"mf-oauth\",\r\n        \"count\": 500,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n    {\r\n        \"resource\": \"mf-sys\",\r\n        \"count\": 500,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n    {\r\n        \"resource\": \"mf-storage\",\r\n        \"count\": 100,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n    {\r\n        \"resource\": \"mf-scheduler\",\r\n        \"count\": 100,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    }\r\n]', '2f2496295023706014fa181fe2b4ffa3', '2026-02-08 10:42:36', '2026-02-08 10:42:36', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"json\"}');

-- ----------------------------
-- Table structure for permissions
-- ----------------------------
DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions`  (
                                `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
                                `resource` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'resource',
                                `action` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'action',
                                UNIQUE INDEX `uk_role_permission`(`role`, `resource`, `action`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of permissions
-- ----------------------------

-- ----------------------------
-- Table structure for roles
-- ----------------------------
DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles`  (
                          `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'username',
                          `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
                          UNIQUE INDEX `idx_user_role`(`username`, `role`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of roles
-- ----------------------------
INSERT INTO `roles` VALUES ('nacos', 'ROLE_ADMIN');

-- ----------------------------
-- Table structure for tenant_capacity
-- ----------------------------
DROP TABLE IF EXISTS `tenant_capacity`;
CREATE TABLE `tenant_capacity`  (
                                    `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                    `tenant_id` varchar(128) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL DEFAULT '' COMMENT 'Tenant ID',
                                    `quota` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '配额，0表示使用默认值',
                                    `usage` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '使用量',
                                    `max_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个配置大小上限，单位为字节，0表示使用默认值',
                                    `max_aggr_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '聚合子配置最大个数',
                                    `max_aggr_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个聚合数据的子配置大小上限，单位为字节，0表示使用默认值',
                                    `max_history_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '最大变更历史数量',
                                    `gmt_create` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                    `gmt_modified` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
                                    PRIMARY KEY (`id`) USING BTREE,
                                    UNIQUE INDEX `uk_tenant_id`(`tenant_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb3 COLLATE = utf8mb3_bin COMMENT = '租户容量信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tenant_capacity
-- ----------------------------
INSERT INTO `tenant_capacity` VALUES (1, 'public', 0, 13, 0, 0, 0, 0, '2026-02-08 10:36:25', '2026-02-08 10:42:36');

-- ----------------------------
-- Table structure for tenant_info
-- ----------------------------
DROP TABLE IF EXISTS `tenant_info`;
CREATE TABLE `tenant_info`  (
                                `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
                                `kp` varchar(128) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NOT NULL COMMENT 'kp',
                                `tenant_id` varchar(128) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NULL DEFAULT '' COMMENT 'tenant_id',
                                `tenant_name` varchar(128) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NULL DEFAULT '' COMMENT 'tenant_name',
                                `tenant_desc` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NULL DEFAULT NULL COMMENT 'tenant_desc',
                                `create_source` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin NULL DEFAULT NULL COMMENT 'create_source',
                                `gmt_create` bigint NOT NULL COMMENT '创建时间',
                                `gmt_modified` bigint NOT NULL COMMENT '修改时间',
                                PRIMARY KEY (`id`) USING BTREE,
                                UNIQUE INDEX `uk_tenant_info_kptenantid`(`kp`, `tenant_id`) USING BTREE,
                                INDEX `idx_tenant_id`(`tenant_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb3 COLLATE = utf8mb3_bin COMMENT = 'tenant_info' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tenant_info
-- ----------------------------

-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
                          `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'username',
                          `password` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'password',
                          `enabled` tinyint(1) NOT NULL COMMENT 'enabled',
                          PRIMARY KEY (`username`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

